mapper.select:
SELECT m.material_id, -- 자재 ID m.material_name, -- 자재명 m.material_type, -- 자재 유형 m.unit, -- 단위 m.safety_stock, -- 안전재고 기준 SUM(mi.quantity) AS quantity, -- 전체 보유 수량 합계 MIN(mi.expiration_date) AS expirationDate, -- 가장 빠른 유통기한 MIN(mi.last_movement_date) AS lastMovementDate, -- 최근 입출고일 GROUP_CONCAT(DISTINCT mi.warehouse_code SEPARATOR ', ') AS warehouseCode -- 보관창고 목록 (콤마 구분) FROM material_inventory mi JOIN material m ON mi.material_id = m.material_id WHERE 1=1
AND ( mi.material_id LIKE CONCAT('%', #{keyword}, '%') OR m.material_name LIKE CONCAT('%', #{keyword}, '%') OR m.material_type LIKE CONCAT('%', #{keyword}, '%') )
GROUP BY m.material_id, m.material_name, m.material_type, m.unit, m.safety_stock ORDER BY m.material_id ASC LIMIT #{pageStart}, #{perPageNum}
